const packageManagerIcons: Record<
    PackageManager,
    React.FC<{ className?: string }>
> = {
    npm: NpmIcon,
    yarn: YarnIcon,
    pnpm: PnpmIcon,
    bun: BunIcon,
};

export const MultiPackageManager: React.FC<MultiPackageManagerProps> = ({
    packageName,
    isDev = false,
}) => {
    const [activeManager, setActiveManager] = useState<PackageManager>("pnpm");
    const [copied, setCopied] = useState(false);

    const flag = isDev ? "-D" : "";

    const commands: Record<PackageManager, React.JSX.Element> = {
        pnpm: (
            <>
                <span className="text-orange-800 dark:text-yellow-300">
                    pnpm
                </span>{" "}
                <span className="dark:text-white">add</span>{" "}
                {flag && <span className="text-gray-500">{flag}</span>}
                <span className="text-red-900 dark:text-[#23d18b]">
                    {packageName.trim()}
                </span>
            </>
        ),
        npm: (
            <>
                <span className="text-orange-800 dark:text-yellow-300">
                    npm
                </span>{" "}
                <span className="dark:text-white">install</span>{" "}
                {flag && <span className="text-gray-500">{flag}</span>}
                <span className="text-red-900 dark:text-[#23d18b]">
                    {packageName.trim()}
                </span>
            </>
        ),
        yarn: (
            <>
                <span className="text-orange-800 dark:text-yellow-300">
                    yarn
                </span>{" "}
                <span className="dark:text-white">add</span>{" "}
                {flag && <span className="text-gray-500">{flag}</span>}
                <span className="text-red-900 dark:text-[#23d18b]">
                    {packageName.trim()}
                </span>
            </>
        ),
        bun: (
            <>
                <span className="text-orange-800 dark:text-yellow-300">
                    bun
                </span>{" "}
                <span className="dark:text-white">add</span>{" "}
                {flag && <span className="text-gray-500">{flag}</span>}
                <span className="text-red-900 dark:text-[#23d18b]">
                    {packageName.trim()}
                </span>
            </>
        ),
    };

    const commandsText: Record<PackageManager, string> = {
        pnpm: `pnpm add ${flag} ${packageName}`.trim(),
        npm: `npm install ${flag} ${packageName}`.trim(),
        yarn: `yarn add ${flag} ${packageName}`.trim(),
        bun: `bun add ${flag} ${packageName}`.trim(),
    };

    const handleCopy = () => {
        navigator.clipboard.writeText(commandsText[activeManager]);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className="w-full max-w-xl overflow-hidden rounded-xl border border-gray-300 bg-gray-100 font-sans text-gray-200 shadow-xl dark:border-gray-700 dark:bg-black">
            {/* Tab Headers */}
            <div className="flex border-gray-300 border-b bg-[#ecf1f6] dark:border-gray-800 dark:bg-black">
                {(Object.keys(commands) as PackageManager[]).map((manager) => {
                    const Icon = packageManagerIcons[manager];

                    return (
                        <button
                            key={manager}
                            onClick={() => setActiveManager(manager)}
                            type="button"
                            className={cn(
                                "flex flex-1 cursor-pointer items-center justify-center gap-1 gap-2 px-1 py-2 font-semibold text-sm transition-colors duration-200",
                                activeManager === manager
                                    ? "border-blue-600 border-b-2 bg-gray-200 text-blue-600 dark:border-indigo-500 dark:bg-gray-900 dark:text-indigo-400"
                                    : "text-gray-400 hover:bg-gray-200 hover:text-gray-700 dark:hover:bg-gray-950 dark:hover:text-gray-200",
                            )}
                        >
                            <Icon className="size-4" />
                            {manager}
                        </button>
                    );
                })}
            </div>

            {/* Code Box */}
            <div className="relative flex items-center justify-between bg-[#f4f7fa] p-4 dark:bg-black">
                <pre className="overflow-x-auto pr-12 font-mono text-slate-950 text-sm dark:text-indigo-300">
                    <code>{commands[activeManager]}</code>
                </pre>

                {/* Copy Button */}
                <button
                    type="button"
                    onClick={handleCopy}
                    className="absolute right-4 cursor-pointer rounded-md border border-gray-200 bg-white p-2 text-gray-400 shadow-md transition-colors hover:bg-blue-600 hover:text-white dark:border-gray-800 dark:bg-gray-800 dark:hover:bg-gray-700 dark:hover:text-gray-200"
                    title="Copy to clipboard"
                >
                    {copied ? (
                        <CheckIcon className="size-5" />
                    ) : (
                        <ClipboardIcon className="size-5" />
                    )}
                </button>
            </div>
        </div>
    );
};
